    "Sangareddy":[17.626,78.087],"Nalgonda":[17.0575,79.2678],"Warangal":[17.9689,79.5941],
    "Karimnagar":[18.4386,79.1288],"Nizamabad":[18.6725,78.094],"Khammam":[17.2473,80.1514],
