    "Peddapalli":[18.6142,79.3836],"Rajanna Sircilla":[18.3841,78.8331],"Siddipet":[18.1022,78.8521],
    "Suryapet":[17.1406,79.6213],"Vikarabad":[17.337,77.902],"Wanaparthy":[16.3624,78.065],
