// ─── ADMIN PANEL ──────────────────────────────────────────────────────────────
function AdminPanel({ listings, setListings, t }) {
  const [tab, setTab] = useState("listings");
  const [users, setUsers] = useState(getUsers());

  const deleteUser = (id) => {
    const updated = users.filter(u=>u.id!==id); saveUsers(updated); setUsers(updated);
  };
  const deleteListing = (id) => { const updated = listings.filter(l=>l.id!==id); setListings(updated); saveListings(updated); };
  const approveListing = (id) => setListings(p=>p.map(l=>l.id===id?{...l,approved:true}:l));

  return (
    <div className="page">
      <h2 className="page-title">{t.adminPanel}</h2>
      <div className="admin-tabs">
        <button className={`admin-tab ${tab==="listings"?"active":""}`} onClick={()=>setTab("listings")}>🏡 {t.allListings} ({listings.length})</button>
        <button className={`admin-tab ${tab==="users"?"active":""}`} onClick={()=>setTab("users")}>👥 {t.allUsers} ({users.length})</button>
      </div>

      {tab==="listings" && (
        <div className="admin-table-wrap">
          <table className="admin-table">
            <thead><tr><th>Title</th><th>Location</th><th>Price</th><th>Seller</th><th>Phone</th><th>Status</th><th>Actions</th></tr></thead>
            <tbody>
              {listings.map(l=>(
                <tr key={l.id}>
                  <td>{l.title}</td>
                  <td>{l.location}</td>
                  <td>₹{Number(l.price).toLocaleString("en-IN")}</td>
                  <td>{l.sellerName}</td>
                  <td><a href={`tel:${l.sellerPhone}`}>{l.sellerPhone}</a></td>
                  <td><span className={`status-badge ${l.approved?"approved":"pending"}`}>{l.approved?"✅ Approved":"⏳ Pending"}</span></td>
                  <td>
                    {!l.approved && <button className="admin-btn approve" onClick={()=>approveListing(l.id)}>✅</button>}
                    <button className="admin-btn delete" onClick={()=>deleteListing(l.id)}>🗑️</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {tab==="users" && (
        <div className="admin-table-wrap">
          <table className="admin-table">
            <thead><tr><th>Name</th><th>Mobile</th><th>District</th><th>Joined</th><th>Actions</th></tr></thead>
            <tbody>
              {users.map(u=>(
                <tr key={u.id}>
                  <td>{u.name}</td>
                  <td><a href={`tel:${u.mobile}`}>{u.mobile}</a></td>
                  <td>{u.district}</td>
                  <td>{u.joinedAt}</td>
                  <td><button className="admin-btn delete" onClick={()=>deleteUser(u.id)}>🗑️</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ─── PROFILE ──────────────────────────────────────────────────────────────────
function ProfilePage({ user, listings, onLogout, t }) {
  const myListings = listings.filter(p=>p.postedBy===user.id);
  const favIds = getFavs(user.id);
  const favListings = listings.filter(p=>favIds.includes(p.id));
  const [tab, setTab] = useState("my");
  return (
    <div className="page">
      <div className="profile-card">
        <div className="profile-avatar">{user.name.charAt(0).toUpperCase()}</div>
        <div className="profile-info">
          <h3>{user.name}</h3>
          <p>📱 {user.mobile}</p>
          <p>📍 {user.district}</p>
          <p>📅 {t.joinedAt} {user.joinedAt}</p>
        </div>
      </div>
      <div className="admin-tabs">
        <button className={`admin-tab ${tab==="my"?"active":""}`} onClick={()=>setTab("my")}>🏡 {t.myListings} ({myListings.length})</button>
        <button className={`admin-tab ${tab==="fav"?"active":""}`} onClick={()=>setTab("fav")}>❤️ {t.favourites} ({favListings.length})</button>
      </div>
      {tab==="my" && (myListings.length===0
        ? <div className="empty"><div className="empty-icon">🏡</div><p>{t.noListings}</p></div>
        : <div className="grid">{myListings.map(p=><PropertyCard key={p.id} prop={p} onContact={()=>{}} userId={user.id} t={t}/>)}</div>)}
      {tab==="fav" && (favListings.length===0
        ? <div className="empty"><div className="empty-icon">❤️</div><p>{t.noFavs}</p></div>
        : <div className="grid">{favListings.map(p=><PropertyCard key={p.id} prop={p} onContact={()=>{}} userId={user.id} t={t}/>)}</div>)}
      <button className="logout-btn" onClick={onLogout}>🚪 {t.logout}</button>
    </div>
  );
}

const getListings = () => JSON.parse(localStorage.getItem("br_listings") || "[]");
const saveListings = (l) => localStorage.setItem("br_listings", JSON.stringify(l));

// ─── MAIN APP ─────────────────────────────────────────────────────────────────
export default function App() {
  const [lang, setLang] = useState("en");
  const t = T[lang];
  const [authMode, setAuthMode] = useState("login");
  const [showForgot, setShowForgot] = useState(false);
  const [user, setUser] = useState(null);
  const [mode, setMode] = useState("home");
  const [listings, setListings] = useState(getListings);
  const [contactProp, setContactProp] = useState(null);
  const [filterType, setFilterType] = useState("All");
  const [filterLoc, setFilterLoc] = useState("All");
  const [search, setSearch] = useState("");
  const [viewMode, setViewMode] = useState("list");
  const [successMsg, setSuccessMsg] = useState("");

  const toast = (msg) => { setSuccessMsg(msg); setTimeout(()=>setSuccessMsg(""),4000); };
  const handleLogin = (u) => { setUser(u); setMode("home"); toast("👋 " + t.welcomeBack + ", " + u.name + "!"); };
  const handleSignup = (u) => { setUser(u); setMode("home"); toast("🎉 " + t.welcome + " " + u.name + "!"); };
  const handleLogout = () => { setUser(null); setAuthMode("login"); setMode("home"); };
  const handleList = (data) => {
    const updated = [data, ...listings];
    setListings(updated);
    saveListings(updated);
    setMode("buy");
    toast("🎉 Property listed successfully!");
  };

  const filtered = listings.filter(p => {
    const byType = filterType==="All" || p.propertyType===filterType;
    const byLoc = filterLoc==="All" || p.location===filterLoc;
    const bySearch = !search || p.title.toLowerCase().includes(search.toLowerCase()) || p.location.toLowerCase().includes(search.toLowerCase());
    return byType && byLoc && bySearch;
  });

  if (!user) {
    if (showForgot) return (
      <>
        <style>{authStyles}</style>
        <div className="lang-bar"><button className={lang==="en"?"lang-active":""} onClick={()=>setLang("en")}>EN</button><button className={lang==="te"?"lang-active":""} onClick={()=>setLang("te")}>తె</button></div>
        <ForgotPassword onBack={()=>setShowForgot(false)} lang={lang}/>
      </>
    );
    return (
      <>
        <style>{authStyles}</style>
        <div className="lang-bar"><button className={lang==="en"?"lang-active":""} onClick={()=>setLang("en")}>EN</button><button className={lang==="te"?"lang-active":""} onClick={()=>setLang("te")}>తె</button></div>
        {authMode==="login"
          ? <LoginForm onLogin={handleLogin} onSwitch={()=>setAuthMode("signup")} onForgot={()=>setShowForgot(true)} lang={lang}/>
          : <SignupForm onSignup={handleSignup} onSwitch={()=>setAuthMode("login")} lang={lang}/>}
      </>
    );
  }

  return (
    <>
      <style>{appStyles}</style>
      <div className="header">
        <div className="logo" onClick={()=>setMode("home")}>
          <img src={LOGO} alt="BHOORAKSHA" className="logo-img" />
          <span className="logo-fallback" style={{display:'none'}}>🛡️</span>
          <div>
            <div className="logo-text">{t.appName}</div>
            <div className="logo-sub">{t.appSub}</div>
          </div>
        </div>
        <nav className="nav">
          <button className={`nav-btn ${mode==="home"?"active":""}`} onClick={()=>setMode("home")}>{t.home}</button>
          <button className={`nav-btn ${mode==="buy"?"active":""}`} onClick={()=>setMode("buy")}>{t.buy}</button>
          {!user.isAdmin && <button className={`nav-btn ${mode==="sell"?"active":""}`} onClick={()=>setMode("sell")}>{t.sell}</button>}
          {user.isAdmin && <button className={`nav-btn ${mode==="admin"?"active":""}`} onClick={()=>setMode("admin")}>{t.admin}</button>}
          {!user.isAdmin && <button className={`nav-btn ${mode==="profile"?"active":""}`} onClick={()=>setMode("profile")}>{t.profile}</button>}
          <div className="lang-toggle">
            <button className={lang==="en"?"lang-active":""} onClick={()=>setLang("en")}>EN</button>
            <button className={lang==="te"?"lang-active":""} onClick={()=>setLang("te")}>తె</button>
          </div>
          <div className="user-chip" onClick={()=>user.isAdmin?handleLogout():setMode("profile")}>
            <div className="user-chip-avatar">{user.isAdmin?"🛡️":user.name.charAt(0).toUpperCase()}</div>
            <span className="user-chip-name">{user.name.split(" ")[0]}</span>
          </div>
        </nav>
      </div>

      {successMsg && <div className="success-bar">{successMsg}</div>}

      {mode==="home" && (
        <div className="hero">
          <div className="hero-badge">Telangana's Premier Land Marketplace</div>
          <p className="welcome-msg">👋 {t.welcome}, {user.name}!</p>
          <h1>{t.heroTitle1} <span>{t.heroTitle2}</span><br/>{t.heroTitle3}</h1>
          <p>{t.heroDesc}</p>
          <div className="hero-actions">
            <button className="hero-btn primary" onClick={()=>setMode("buy")}>{t.browse}</button>
            {!user.isAdmin && <button className="hero-btn secondary" onClick={()=>setMode("sell")}>{t.listProp}</button>}
          </div>
          <div className="stats">
            <div className="stat"><div className="stat-num">{listings.length}+</div><div className="stat-label">{t.listings}</div></div>
            <div className="stat"><div className="stat-num">33</div><div className="stat-label">{t.districts}</div></div>
            <div className="stat"><div className="stat-num">100%</div><div className="stat-label">{t.directDeals}</div></div>
          </div>
        </div>
      )}

      {mode==="buy" && (
        <div className="page">
          <div className="page-header">
            <div className="page-title">{t.availableProps}</div>
            <div className="view-toggle">
              <button className={viewMode==="list"?"active":""} onClick={()=>setViewMode("list")}>📋</button>
              <button className={viewMode==="map"?"active":""} onClick={()=>setViewMode("map")}>🗺️</button>
            </div>
          </div>
          <input className="search-bar" value={search} onChange={e=>setSearch(e.target.value)} placeholder={t.searchPlaceholder} />
          <div className="filters">
            <select className="filter-select" value={filterType} onChange={e=>setFilterType(e.target.value)}>
              <option value="All">{t.allTypes}</option>
              {PROPERTY_TYPES.map(tp=><option key={tp}>{tp}</option>)}
            </select>
            <select className="filter-select" value={filterLoc} onChange={e=>setFilterLoc(e.target.value)}>
              <option value="All">{t.allDistricts}</option>
              {LOCATIONS.map(l=><option key={l}>{l}</option>)}
            </select>
          </div>
          <div className="listing-count">{filtered.length} {t.found}</div>
          {viewMode==="list"
            ? (filtered.length>0
              ? <div className="grid">{filtered.map(p=><PropertyCard key={p.id} prop={p} onContact={setContactProp} userId={user.id} t={t}/>)}</div>
              : <div className="empty"><div className="empty-icon">🔍</div><p>No properties found.</p></div>)
            : <MapView listings={filtered} onContact={setContactProp} userId={user.id} t={t}/>}
        </div>
      )}

      {mode==="sell" && <SellForm onSubmit={handleList} onCancel={()=>setMode("home")} user={user} t={t}/>}
      {mode==="profile" && <ProfilePage user={user} listings={listings} onLogout={handleLogout} t={t}/>}
      {mode==="admin" && <AdminPanel listings={listings} setListings={setListings} t={t}/>}
      <ContactModal prop={contactProp} onClose={()=>setContactProp(null)} t={t}/>
    </>
  );
}

